SELECT c.constructorid, c.name, cr.points FROM constructors AS c JOIN constructorresults AS cr ON c.constructorid = cr.constructorid JOIN races AS r ON cr.raceid = r.raceid JOIN circuits AS ci ON r.circuitid = ci.circuitid JOIN target AS t ON c.constructorid = t.driverid WHERE (ci.country IN ('Australia', 'USA', 'UK', 'Germany', 'Brazil'))
